INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (0, 311006, 8, 0.5, 311, 0, 100911, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！", 0, 0, 11);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES ("", 311007, "", "", 311, "", 311006, "", "", "", 91);
