INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES ("", 312002, 1, "", 312, "", 101831, "nop_talk_joy1", 0.2, "", 3);
